// Explodir URLs p/ Exames — 1 saída, itens marcados por "route": 'db' ou 'secretaria'

const src = $json;

function normTs(ts) {
  try { return new Date(ts).toISOString(); } catch { return new Date().toISOString(); }
}

function toUrlArray(raw) {
  if (Array.isArray(raw)) return raw;
  if (typeof raw === 'string' && raw.trim()) {
    const s = raw.trim();
    if (s.startsWith('[') && s.endsWith(']')) {
      try { const a = JSON.parse(s); if (Array.isArray(a)) return a; } catch {}
      return [s];
    }
    if (s.includes(',')) return s.split(',').map(x => x.trim()).filter(Boolean);
    return [s];
  }
  return [];
}

const raw = src.data_url ?? src.urls ?? null;
let urls = toUrlArray(raw);
urls = Array.from(new Set(urls.filter(Boolean))).sort();

const out = [];

// Itens para o BANCO (1 por URL) - PRIMEIRO
for (const u of urls) {
  out.push({
    json: {
      ...src,
      route: 'db',
      has_url: true,
      url_file: u,
      file_type: 'file',
      timestamp: normTs(src.timestamp),
    }
  });
}

// Item único para a SECRETÁRIA - ÚLTIMO (sempre executa)
out.push({
  json: {
    ...src,
    route: 'secretaria',
    has_url: urls.length > 0,
    url_para_secretaria: urls.length ? String(urls[0]) : '',
    file_type: src.tipo_arquivo ?? (urls.length ? 'file' : 'text_message'),
    timestamp: normTs(src.timestamp),
  }
});

return out;

