// Fallback expandido contra output vazio do AI Agent (bug LangChain x Gemini multi-modal).
// Detecta qual tool de ação foi chamada e injeta mensagem contextual no lugar.
// A regra 10 do systemMessage agora instrui o modelo a separar texto+tool em turnos
// distintos. Este código é a rede de segurança caso o modelo escape da regra.

const input = $input.first().json;
const texto = (input.output || '').trim();
const steps = input.intermediateSteps || [];

function stepWithTool(name) {
  return steps.find(s => s.action?.tool === name);
}

function parseObs(obs) {
  if (!obs) return null;
  if (typeof obs === 'object') return obs;
  try { return JSON.parse(obs); } catch { return null; }
}

let formatado;

if (!texto) {
  // Output vazio: tenta gerar fallback contextual com base na tool chamada.
  if (stepWithTool('Escalar_humano')) {
    formatado = 'Vou transferir seu atendimento para a nossa equipe, que continuará falando com você por aqui em instantes.';
  } else {
    const safeCreate = stepWithTool('Call_safe_create_event___Gate_Servidor_pra_Agendamento')
                    || stepWithTool('safe_create_event');
    const safeCancel = stepWithTool('Call_TOOL___safe_cancel_booking')
                    || stepWithTool('safe_cancel_booking');
    const safeUpdate = stepWithTool('Call_TOOL___safe_update_booking')
                    || stepWithTool('safe_update_booking');

    if (safeCreate) {
      const obs = parseObs(safeCreate.observation);
      if (obs?.success === true) {
        formatado = 'Pronto! Seu agendamento foi criado com sucesso. Em instantes você recebe os detalhes da consulta.';
      } else if (obs?.reason === 'slot_taken') {
        formatado = 'Esse horário acabou de ser ocupado por outro paciente. Posso verificar outras opções próximas pra você?';
      } else if (obs?.message) {
        formatado = 'Tive uma dificuldade ao processar o agendamento: ' + String(obs.message).slice(0, 120) + '. Podemos tentar outro horário?';
      } else {
        formatado = 'Não consegui confirmar o agendamento agora. Pode me confirmar o horário desejado pra eu tentar de novo?';
      }
    } else if (safeCancel) {
      const obs = parseObs(safeCancel.observation);
      if (obs?.success === true) {
        formatado = 'Seu cancelamento foi processado. Posso ajudar com mais alguma coisa?';
      } else {
        formatado = 'Tive um problema ao cancelar. Pode confirmar de qual consulta você quer cancelar?';
      }
    } else if (safeUpdate) {
      const obs = parseObs(safeUpdate.observation);
      if (obs?.success === true) {
        formatado = 'Sua remarcação está confirmada. Em instantes envio os novos detalhes.';
      } else {
        formatado = 'Tive uma dificuldade ao remarcar. Pode me confirmar o novo horário desejado?';
      }
    } else {
      formatado = 'Desculpe, tive uma pequena instabilidade. Pode repetir sua última mensagem?';
    }
  }
} else {
  formatado = texto
    .replace(/\*\*(.*?)\*\*/g, '*$1*')
    .replace(/^#{1,6}\s*/gm, '')
    .trim();
}

return [{ json: { text: formatado } }];

// Computa contexto temporal em BRT de forma explícita e auditável
const now = $now.setZone('America/Sao_Paulo');

return {
  json: {
    ...item.json,
    _ctx_data_hoje:      now.toFormat('dd/MM/yyyy'),
    _ctx_data_iso:       now.toFormat('yyyy-MM-dd'),
    _ctx_dia_semana:     now.toFormat('cccc'),
    _ctx_hora_atual_brt: now.toFormat('HH:mm'),
    _ctx_timestamp_iso:  now.toISO(),
  }
};

// Converte timestamps UTC para BRT legível antes de passar para a IA
// Previne que a IA receba timestamps brutos e calcule timezone incorretamente

const item = $input.item.json;

function utcToBRT(isoString) {
  if (!isoString) return null;
  try {
    const dt = new Date(isoString);
    if (isNaN(dt.getTime())) return isoString;
    // BRT = UTC-3
    const brtTime = new Date(dt.getTime() - 3 * 60 * 60 * 1000);
    const dias = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
    const dayName = dias[brtTime.getUTCDay()];
    const dd = String(brtTime.getUTCDate()).padStart(2, '0');
    const mm = String(brtTime.getUTCMonth() + 1).padStart(2, '0');
    const yyyy = brtTime.getUTCFullYear();
    const hh = String(brtTime.getUTCHours()).padStart(2, '0');
    const min = String(brtTime.getUTCMinutes()).padStart(2, '0');
    const timeStr = min === '00' ? `${hh}h` : `${hh}h${min}`;
    return `${dayName}, ${dd}/${mm}/${yyyy} às ${timeStr} (BRT)`;
  } catch(e) { return isoString; }
}

const output = { ...item };

if (output.last_slot_start) {
  output.last_slot_start_brt = utcToBRT(output.last_slot_start);
}
if (output.last_slot_end) {
  output.last_slot_end_brt = utcToBRT(output.last_slot_end);
}

return { json: output };

