const infoItems = $('Info').all();          // itens do nó Info (payload atual do webhook)
const info = $('Info').first()?.json || {}; // dados do webhook atual

// 1) Fila vazia -> NÃO BLOQUEIA: passa o Info adiante para manter o fluxo
if (!itens.length) {
  return infoItems && infoItems.length ? infoItems : itens; // fallback se não houver Info
}

// 2) Com fila: compara último item da fila com o id do webhook atual
const ultima = itens[itens.length - 1];
const idUltima = ultima?.json?.id_mensagem;
const idWorkflow = info?.id_mensagem;

// Se faltar algum ID, não bloqueia (evita falso negativo por payload incompleto)
if (!idUltima || !idWorkflow) {
  return itens;
}

// 3) IDs diferentes -> BLOQUEIA (aguarda próxima rodada do Wait/Buscar)
if (String(idUltima) !== String(idWorkflow)) {
  return [];
}

// 4) Tudo certo -> NÃO BLOQUEIA: libera a fila (segue normalmente)
return itens;

